const items = $input.all();
const results = [];

for (const item of items) {
  // Récupérer le callback_data
  const callbackData = item.json.callback_query?.data || item.json.data;

  // Extraire le texte du message
  const messageText = item.json.callback_query?.message?.text || '';

  // Fonction pour extraire une valeur après un label
  function extractValue(text, label) {
    const regex = new RegExp(`${label}\\s*:\\s*([^\\n]+)`, 'i');
    const match = text.match(regex);
    return match ? match[1].trim() : 'Non disponible';
  }

  // Extraire toutes les informations du message
  const dossierNumero = extractValue(messageText, '📋 Numéro de dossier');
  const nomComplet = extractValue(messageText, '👤 Nom complet');
  const matricule = extractValue(messageText, '🆔 Matricule');
  const poste = extractValue(messageText, '📍 Poste');
  const cin = extractValue(messageText, '🆔 CIN');
  const dateCreation = extractValue(messageText, '📅 Date');

  // ✅ VÉRIFICATION DU FORMAT DU NUMÉRO DE DOSSIER
  const dossierRegex = /^[A-Z]{4}\d{6}$/; // Format: 4 lettres + 6 chiffres (ex: VRDG000003)
  const isDossierValid = dossierRegex.test(dossierNumero);

  // ✅ VÉRIFICATION DU TYPE DE MESSAGE
  const isCallbackQuery = !!item.json.callback_query;
  const messageType = isCallbackQuery ? 'callback_query' : 'autre';

  // Log pour debug
  console.log(`Message type: ${messageType}, Dossier: ${dossierNumero}, Valid: ${isDossierValid}`);

  // ❌ IGNORER SI CE N'EST PAS UN CALLBACK QUERY OU SI LE DOSSIER EST INVALIDE
  if (!isCallbackQuery) {
    console.log(`⚠️ Message ignoré - Type: ${messageType}`);
    continue; // Passer au message suivant
  }

  if (!isDossierValid) {
    console.log(`⚠️ Numéro de dossier invalide: ${dossierNumero}`);
    continue; // Passer au message suivant
  }

  // Séparer prénom et nom
  const nomParts = nomComplet.split(' ');
  const prenom = nomParts[0] || '';
  const nom = nomParts.slice(1).join(' ') || '';

  // Déterminer la réponse (oui/non) depuis le callback_data
  let reponse = 'unknown';
  if (callbackData.includes('_oui')) {
    reponse = 'oui';
  } else if (callbackData.includes('_non')) {
    reponse = 'non';
  }

  // ❌ IGNORER SI LA RÉPONSE N'EST PAS RECONNUE
  if (reponse === 'unknown') {
    console.log(`⚠️ Réponse non reconnue dans callback_data: ${callbackData}`);
    continue;
  }

  // Préparer le payload de mise à jour
  const updatePayload = {
    YNUM_0: dossierNumero,
    YVALIDG_0: reponse === 'oui' ? true : false,
    YDATVAL_0: new Date().toISOString().split('T')[0], // Format YYYY-MM-DD
    YCOMM_0: reponse === 'oui' ? 'Validé par PDG via Telegram' : 'Refusé par PDG via Telegram'
  };

  results.push({
    json: {
      // ✅ INFORMATIONS DE VALIDATION
      is_valid_message: true,
      message_type: messageType,
      dossier_format_valid: isDossierValid,

      // Informations du webhook
      webhook_data: {
        dossier: dossierNumero,
        email: 'elghalbzouri.hicham01@gmail.com',
        prenom: prenom,
        nom: nom,
        matricule: matricule,
        poste: poste,
        cin: cin,
        reponse: reponse
      },

      // Informations principales
      dossier: dossierNumero,
      reponse: reponse,
      email: 'elghalbzouri.hicham01@gmail.com',
      telegram_id: item.json.callback_query?.from?.id || null,

      // Statut et dates
      statut: reponse === 'oui' ? 'Validé' : 'Refusé',
      date_validation: new Date().toISOString().split('T')[0],
      date_traitement: new Date().toISOString(),

      // Payload pour la mise à jour Sage
      updatePayload: updatePayload,

      // Informations du candidat
      candidat_info: {
        prenom: prenom,
        nom: nom,
        nom_complet: nomComplet,
        matricule: matricule,
        poste: poste,
        cin: cin,
        date_creation: dateCreation
      },

      // Informations Telegram
      telegram_info: {
        callback_query_id: item.json.callback_query?.id,
        chat_id: item.json.callback_query?.from?.id,
        message_id: item.json.callback_query?.message?.message_id,
        user_first_name: item.json.callback_query?.from?.first_name,
        user_last_name: item.json.callback_query?.from?.last_name
      },

      // Message de réponse pour Telegram
      telegram_response: `${reponse === 'oui' ? '✅ Validation effectuée' : '❌ Refus enregistré'}\n\n` +
                        `📋 Dossier: ${dossierNumero}\n` +
                        `👤 Candidat: ${nomComplet}\n` +
                        `🆔 Matricule: ${matricule}\n` +
                        `📍 Poste: ${poste}\n` +
                        `📊 Statut: ${reponse === 'oui' ? 'Validé' : 'Refusé'}\n\n` +
                        `✅ Le dossier a été ${reponse === 'oui' ? 'validé' : 'refusé'} avec succès !`,

      // Données brutes pour debug
      raw_callback_data: callbackData,
      raw_message_text: messageText
    }
  });
}

// ✅ LOG FINAL
console.log(`Total messages traités: ${results.length}/${items.length}`);

return results;

const items = $input.all();
const results = [];

for (const item of items) {
  const processData = $('Process Telegram Callback').item.json;
  const putData = $('PUT - Update Dossier').item.json; // Données du PUT
  const dossierFromGet = item.json; // Données du GET depuis Sage

  const reponse = processData.reponse;
  const dossierNumero = dossierFromGet.YNUM;
  const email = processData.email;
  const telegram_id = processData.telegram_id;

  // Récupérer les informations personnelles depuis webhook_data
  const webhookData = processData.webhook_data || {};
  const prenom = webhookData.prenom || 'Non renseigné';
  const nom = webhookData.nom || 'Non renseigné';
  const nomComplet = `${prenom} ${nom}`.trim();
  const matricule = webhookData.matricule || 'Non renseigné';
  const poste = webhookData.poste || 'Non renseigné';
  const cin = webhookData.cin || 'Non renseigné';

  // Extraire le statut de validation depuis YVALIDG (du PUT qui est la source de vérité)
  const isValidated = putData.YVALIDG === true;

  // Récupérer le message de diagnostic depuis le PUT (prioritaire)
  let diagnosticMessage = '';
  let isAlreadyProcessed = false;

  // Vérifier d'abord dans le PUT data (source principale)
  if (putData.$diagnoses && Array.isArray(putData.$diagnoses)) {
    const diagnosis = putData.$diagnoses.find(d => d.$severity === 'info');
    if (diagnosis && diagnosis.$message) {
      diagnosticMessage = diagnosis.$message;
      // Vérifier si le dossier était déjà validé
      if (diagnosticMessage.toLowerCase().includes('deja valide') || 
          diagnosticMessage.toLowerCase().includes('déjà validé')) {
        isAlreadyProcessed = true;
      }
    }
  }

  // Si pas de diagnostic dans PUT, vérifier dans GET (fallback)
  if (!diagnosticMessage && dossierFromGet.$diagnoses && Array.isArray(dossierFromGet.$diagnoses)) {
    const diagnosis = dossierFromGet.$diagnoses.find(d => d.$severity === 'info');
    if (diagnosis && diagnosis.$message) {
      diagnosticMessage = diagnosis.$message;
      if (diagnosticMessage.toLowerCase().includes('deja valide') || 
          diagnosticMessage.toLowerCase().includes('déjà validé')) {
        isAlreadyProcessed = true;
      }
    }
  }

  // Extraire les informations du dossier Sage (priorité au PUT)
  const etag = putData.$etag || dossierFromGet.$etag;
  const dateValidationSage = putData.YDATVAL ? new Date(putData.YDATVAL).toLocaleDateString('fr-FR') : 
                              (dossierFromGet.YDATVAL ? new Date(dossierFromGet.YDATVAL).toLocaleDateString('fr-FR') : 'N/A');
  const dateValidation = putData.YDATVAL || dossierFromGet.YDATVAL || new Date().toISOString().split('T')[0];
  const commentaire = putData.YCOMM || dossierFromGet.YCOMM || '';

  // Déterminer le statut dynamique basé sur YVALIDG et les diagnostics
  let statut;
  let emoji;

  if (isAlreadyProcessed) {
    statut = isValidated ? 'Déjà validé' : 'Déjà traité';
    emoji = '⚠️';
  } else {
    statut = isValidated ? 'Validé' : 'Refusé';
    emoji = isValidated ? '✅' : '❌';
  }

  // Message Telegram dynamique
  let message_text = `${emoji} *${statut.toUpperCase()}*
📋 Dossier: \`${dossierNumero}\`
👤 ${nomComplet}
📍 ${poste}
🆔 ${matricule}
📅 ${new Date().toLocaleDateString('fr-FR')}`;

  // Ajouter le message de diagnostic s'il existe
  if (diagnosticMessage) {
    message_text += `\n\n💬 _${diagnosticMessage}_`;
  }

  // Ajouter la date de validation si le dossier était déjà validé
  if (isAlreadyProcessed && dateValidationSage !== 'N/A') {
    message_text += `\n📅 _Validé le ${dateValidationSage}_`;
  }

  results.push({
    json: {
      dossier: dossierNumero,
      reponse: reponse,
      email: email,
      telegram_id: telegram_id,
      statut: statut,
      date_validation: dateValidation,
      message_text: message_text,

      // Informations personnelles du candidat
      candidat_info: {
        prenom: prenom,
        nom: nom,
        nom_complet: nomComplet,
        matricule: matricule,
        poste: poste,
        cin: cin
      },

      // Informations de diagnostic
      diagnostic_info: {
        message: diagnosticMessage,
        is_already_processed: isAlreadyProcessed,
        is_validated: isValidated,
        source: diagnosticMessage ? (putData.$diagnoses ? 'PUT' : 'GET') : 'none'
      },

      // Données Sage complètes
      sage_data: {
        etag: etag,
        commentaire: commentaire,
        date_validation_sage: dateValidationSage
      },

      success: true,
      skipUpdate: isAlreadyProcessed // Flag pour sauter le PUT si déjà traité
    }
  });
}

return results;
